static float sensor_value = 0.0f; // 禁止外部直接访问

void Sensor_Init(void) { /* HW config */ }
float Sensor_GetValue(void) { return sensor_value; }

/* sensor.h */
typedef struct Sensor_t *SensorHandle_t;
SensorHandle_t Sensor_Create(void);
float Sensor_Read(SensorHandle_t h);

/* sensor.c */
#include "stm32f4xx_hal.h"
struct Sensor_t {
  ADC_HandleTypeDef *hadc;
  uint32_t channel;
};

float Sensor_Read(SensorHandle_t h) {
  HAL_ADC_Start(h->hadc);
  if(HAL_ADC_PollForConversion(h->hadc, 10) == HAL_OK) {
     return (float)HAL_ADC_GetValue(h->hadc);
  }
  return 0.0f;
}

